// SongRequestsSearchChannelOrVideo is the resolver for the songRequestsSearchChannelOrVideo field.
func (r *queryResolver) SongRequestsSearchChannelOrVideo(ctx context.Context, opts gqlmodel.SongRequestsSearchChannelOrVideoOpts) (*gqlmodel.SongRequestsSearchChannelOrVideoResponse, error) {
	response := &gqlmodel.SongRequestsSearchChannelOrVideoResponse{
		Items: make([]gqlmodel.SongRequestsSearchChannelOrVideoItem, 0, len(opts.Query)),
	}

	getThumbNailUrl := func(url string) string {
		return strings.Replace(url, "http://", "https://", 1)
	}

	if len(opts.Query) == 0 {
		return response, nil
	}

	var mu sync.Mutex
	loParallel.ForEach(
		opts.Query,
		func(query string, _ int) {
			if query == "" {
				return
			}

			var search *ytsearch.SearchClient
			if opts.Type == gqlmodel.SongRequestsSearchChannelOrVideoOptsTypeChannel {
				search = ytsearch.ChannelSearch(query)
			} else {
				search = ytsearch.VideoSearch(query)
			}

			res, err := search.Next()
			if err != nil {
				r.deps.Logger.Error(
					"cannot find",
					slog.String("query", query),
				)
				return
			}

			mu.Lock()
			defer mu.Unlock()
			if opts.Type == gqlmodel.SongRequestsSearchChannelOrVideoOptsTypeChannel {
				channels := lo.Map(
					res.Channels,
					func(item *ytsearch.ChannelItem, _ int) gqlmodel.SongRequestsSearchChannelOrVideoItem {
						thumb := getThumbNailUrl(item.Thumbnails[len(item.Thumbnails)-1].URL)
						return gqlmodel.SongRequestsSearchChannelOrVideoItem{
							ID:        item.ID,
							Title:     item.Title,
							Thumbnail: thumb,
						}
					},
				)
				response.Items = append(
					response.Items,
					channels...,
				)
			} else {
				videos := lo.Map(
					res.Videos,
					func(item *ytsearch.VideoItem, _ int) gqlmodel.SongRequestsSearchChannelOrVideoItem {
						thumb := getThumbNailUrl(item.Thumbnails[len(item.Thumbnails)-1].URL)

						return gqlmodel.SongRequestsSearchChannelOrVideoItem{
							ID:        item.ID,
							Title:     item.Title,
							Thumbnail: thumb,
						}
					},
				)
				response.Items = append(
					response.Items,
					videos...,
				)
			}
		},
	)

	return response, nil
}

// SongRequestsPublicQueue is the resolver for the songRequestsPublicQueue field.
func (r *queryResolver) SongRequestsPublicQueue(ctx context.Context, channelID string) ([]gqlmodel.SongRequestPublic, error) {
	queue, err := r.deps.SongRequestsService.GetPublicQueue(ctx, channelID)
	if err != nil {
		return nil, gqlerrors.HandleError(err)
	}

	mapped := make([]gqlmodel.SongRequestPublic, 0, len(queue))
	for _, song := range queue {
		mapped = append(mapped, mappers.SongRequestPublicTo(song))
	}

	return mapped, nil
}

// SongRequestWidgetData is the resolver for the songRequestWidgetData field.
func (r *queryResolver) SongRequestWidgetData(ctx context.Context, channelID uuid.UUID) (*gqlmodel.SongRequestWidgetData, error) {
	channelIDStr := channelID.String()

	playbackState, err := r.deps.SongRequestPlaybackStateService.GetState(ctx, channelIDStr)
	if err != nil {
		return nil, gqlerrors.HandleError(fmt.Errorf("failed to get playback state: %w", err))
	}
	settingsVolume := getSongRequestSettingsVolume(ctx, r.deps.Gorm, channelIDStr)

	var gqlPlaybackState *gqlmodel.SongRequestPlaybackState
	if playbackState != nil {
		gqlPlaybackState = &gqlmodel.SongRequestPlaybackState{
			VideoID:   playbackState.VideoID,
			Title:     playbackState.Title,
			Position:  playbackState.Position,
			IsPlaying: playbackState.IsPlaying,
			Volume:    playbackState.Volume,
			UpdatedAt: time.UnixMilli(playbackState.UpdatedAt),
		}
	}

	var queue []model.RequestedSong
	if err := r.deps.Gorm.WithContext(ctx).
		Where(`"channelId" = ? AND "deletedAt" IS NULL`, channelIDStr).
		Order(`"queuePosition" asc`).
		Find(&queue).Error; err != nil {
		return nil, gqlerrors.HandleError(fmt.Errorf("failed to get queue: %w", err))
	}

	gqlQueue := make([]gqlmodel.SongRequestQueueItem, 0, len(queue))
	for _, song := range queue {
		songLink := fmt.Sprintf("https://youtu.be/%s", song.VideoID)
		if song.SongLink.Valid {
			songLink = song.SongLink.String
		}

		gqlQueue = append(gqlQueue, gqlmodel.SongRequestQueueItem{
			ID:                   song.VideoID,
			Title:                song.Title,
			SongLink:             songLink,
			DurationSeconds:      int(song.Duration),
			OrderedByName:        song.OrderedByName,
			OrderedByDisplayName: song.OrderedByDisplayName.String,
			QueuePosition:        song.QueuePosition,
			CreatedAt:            song.CreatedAt,
		})
	}

	return &gqlmodel.SongRequestWidgetData{
		PlaybackState: gqlPlaybackState,
		Queue:         gqlQueue,
		Volume:        settingsVolume,
	}, nil
}

// ChannelByAPIKey is the resolver for the channelByApiKey field.
func (r *queryResolver) ChannelByAPIKey(ctx context.Context, apiKey string) (*gqlmodel.ChannelByAPIKeyResult, error) {
	// Try channel API key first
	channel, err := r.deps.ChannelsRepository.GetByApiKey(ctx, apiKey)
	if err == nil && !channel.IsNil() {
		return mapChannelByAPIKeyResult(channel), nil
	}
	if err != nil && !errors.Is(err, channelsrepository.ErrNotFound) {
		return nil, gqlerrors.HandleError(fmt.Errorf("failed to get channel by api key: %w", err))
	}

	// Fallback to user API key
	user, err := r.deps.UsersRepository.GetByApiKey(ctx, apiKey)
	if err != nil {
		if errors.Is(err, usersmodel.ErrNotFound) {
			return nil, nil
		}
		return nil, gqlerrors.HandleError(fmt.Errorf("failed to get user by api key: %w", err))
	}

	if user.IsNil() {
		return nil, nil
	}

	channel, err = r.deps.ChannelService.GetChannelByBindingUserID(ctx, user.Platform, user.ID)
	if err != nil {
		if errors.Is(err, channelsrepository.ErrNotFound) {
			return nil, nil
		}
		return nil, gqlerrors.HandleError(fmt.Errorf("failed to get channel by platform user id: %w", err))
	}
	if channel.IsNil() {
		return nil, nil
	}

	return mapChannelByAPIKeyResult(channel), nil
}

